using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    // The default resolver handles any type at runtime via reflection.
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ── 1. Strongly-typed metadata ──────────────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type handled: {personInfo.Type.Name}");
Console.WriteLine($"Object converter: {personInfo.Converter.GetType().Name}");

// ── 2. Probe without throwing ───────────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata is
// unavailable. Here we test with a type the resolver *does* know and
// one where we remove the resolver so it won't.
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? probed))
    Console.WriteLine($"Probe succeeded for Person – kind: {probed.Kind}");
else
    Console.WriteLine("Probe: Person metadata not available");

// Now try with an options instance that has *no* resolver at all.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };
if (empty.TryGetTypeInfo<Order>(out _))
    Console.WriteLine("Probe succeeded for Order");
else
    Console.WriteLine("Probe: Order metadata not available (expected)");

// ── Types used in the demo ──────────────────────────────────────────────
record Person(string Name, int Age);
record Order(int Id, decimal Total);

